# Mark test function for database access
@pytest.mark.django_db
def test_user_creation():
    user = User.objects.create(email="test@example.com")
    assert user.pk is not None

# For fixtures needing database access
@pytest.fixture
def user(db):  # Request 'db' fixture explicitly
    return User.objects.create(email="test@example.com")

# Missing @pytest.mark.django_db - raises "no database access allowed"
def test_user_creation():
    user = User.objects.create(email="test@example.com")
    assert user.pk is not None

# Fixture missing db parameter - creates data outside transaction
@pytest.fixture
def user():
    return User.objects.create(email="test@example.com")

# Default: db fixture with auto-rollback
@pytest.mark.django_db
def test_user_creation(db):
    user = User.objects.create(email="test@example.com")
    assert user.pk is not None  # pk exists but is rolled back after test

# Testing transactions explicitly
@pytest.mark.django_db(transaction=True)  # or use transactional_db fixture
def test_payment_rollback(transactional_db):
    with pytest.raises(PaymentError):
        PaymentService.process_with_rollback(order, token="failing")
    order.refresh_from_db()
    assert order.status == "pending"  # Verified rolled back

# Testing ID sequences
@pytest.mark.django_db
def test_order_number_auto_increment(django_db_reset_sequences):
    order1 = Order.objects.create(user=user)
    order2 = Order.objects.create(user=user)
    assert order2.id == order1.id + 1  # IDs are sequential

@pytest.fixture
def authenticated_client(api_client, user):
    """API client authenticated as regular user."""
    api_client.force_authenticate(user=user)
    yield api_client
    api_client.force_authenticate(user=None)

@pytest.mark.django_db
class TestUserCreateAPI:
    endpoint = "/api/v1/users/"

    def test_requires_authentication(self, api_client):
        """Returns 401 for unauthenticated requests."""
        response = api_client.get(self.endpoint)
        assert response.status_code == status.HTTP_401_UNAUTHORIZED

    def test_creates_user(self, admin_client):
        """Admin can create new users."""
        payload = {"email": "newuser@example.com", "name": "New User"}
        response = admin_client.post(self.endpoint, payload, format="json")
        assert response.status_code == status.HTTP_201_CREATED
        assert response.data["email"] == payload["email"]

    @pytest.mark.parametrize("field,value,error", [
        ("email", "invalid", "Enter a valid email address"),
        ("email", "", "This field may not be blank"),
        ("name", "", "This field may not be blank"),
    ])
    def test_validation_errors(self, admin_client, field, value, error):
        """Returns validation errors for invalid data."""
        payload = {"email": "test@example.com", "name": "Test"}
        payload[field] = value
        response = admin_client.post(self.endpoint, payload, format="json")
        assert response.status_code == status.HTTP_400_BAD_REQUEST
        assert error in str(response.data[field])

from unittest.mock import patch, MagicMock import responses from freezegun import freeze_time
@patch("apps.payments.services.stripe") def test_creates_stripe_charge(mock_stripe, order): """Creates Stripe charge with correct parameters.""" mock_stripe.Charge.create.return_value = MagicMock( id="ch_123", status="succeeded" )
result = PaymentService.process_payment(order=order, token="tok_visa")
mock_stripe.Charge.create.assert_called_once_with( amount=int(order.total * 100), currency="usd", source="tok_visa" ) assert result.stripe_charge_id == "ch_123"
@responses.activate def test_sends_webhook_notification(order): """Sends webhook with correct payload.""" responses.add( responses.POST, "https://api.partner.com/webhooks/orders", json={"status": "received"}, status=200 )
result = WebhookService.notify_order_created(order) assert result["status"] == "received"
@freeze_time("2025-01-15 12:00:00") def test_coupon_is_valid_before_expiry(coupon_factory): """Coupon is valid before expiration date.""" coupon = coupon_factory(expires_at=datetime(2025, 1, 20, 12, 0, 0)) assert coupon.is_valid() is True

# tests/fixtures/orders.py import pytest
@pytest.fixture def order_with_items(order_factory, product_factory): """Order with 3 items ready for checkout.""" products = [product_factory() for _ in range(3)] order = order_factory(items=[ {"product": p, "quantity": 2} for p in products ]) return order
@pytest.fixture def paid_order(order_with_items, payment_factory): """Order with completed payment.""" payment_factory( order=order_with_items, status="completed", amount=order_with_items.total ) order_with_items.status = "paid" order_with_items.save() return order_with_items
# tests/integration/test_fulfillment.py def test_fulfill_paid_order(paid_order): """Only paid orders can be fulfilled.""" result = fulfill_order(paid_order) assert result.status == "shipped"
